package com.fmcg.ecommerce.controller.admin; import com.fmcg.ecommerce.common.ApiResponse; import io.swagger.v3.oas.annotations.Operation; import io.swagger.v3.oas.annotations.tags.Tag; import org.springframework.http.ResponseEntity; import org.springframework.security.access.prepost.PreAuthorize; import org.springframework.web.bind.annotation.*; import java.util.ArrayList; import java.util.HashMap; import java.util.List; import java.util.Map; @RestController @RequestMapping("/api/v1/admin/delivery") @Tag(name = "Admin Delivery", description = "Fleet and delivery management APIs") public class AdminDeliveryController { @GetMapping("/fleet") @PreAuthorize("hasRole('ADMIN')") @Operation(summary = "Get delivery fleet/riders") public ResponseEntity<ApiResponse<List<Map<String, Object>>>> getFleet() { return ResponseEntity.ok(ApiResponse.ok(new ArrayList<>())); } @PostMapping("/fleet") @PreAuthorize("hasRole('ADMIN')") @Operation(summary = "Add a new rider") public ResponseEntity<ApiResponse<Map<String, Object>>> addRider(@RequestBody Map<String, Object> request) { return ResponseEntity.ok(ApiResponse.ok("Rider added successfully", request)); } }
